import json

def confirmAuth(headers):
    token_str = headers.get('AuthToken')
    if not token_str:
        return None
    try:
        decoded = base64.b64decode(token_str).decode('utf-8')
        token = json.loads(decoded)
        if 'is_valid' in token and token['is_valid']:
            return token['data']
        return None
    except:
        return None

